class PIIMaskingUtil:
    """Utility class for masking PII data in logs and error messages."""

    @staticmethod
    def mask_email(email: str) -> str:
        if not email or '@' not in email:
            return '***'
        local, domain = email.rsplit('@', 1)
        if len(local) <= 2:
            masked_local = '*' * len(local)
        else:
            masked_local = local[0] + '*' * (len(local) - 2) + local[-1]
        return f"{masked_local}@{domain}"

    @staticmethod
    def mask_phone(phone: str) -> str:
        if not phone:
            return '***'
        digits = ''.join(c for c in phone if c.isdigit())
        if len(digits) <= 4:
            return '***'
        return '*' * (len(digits) - 4) + digits[-4:]

    @staticmethod
    def mask_address(address: str) -> str:
        if not address:
            return '***'
        parts = address.split()
        if len(parts) <= 2:
            return '***'
        return '*** ' + ' '.join(parts[-2:])

    @staticmethod
    def mask_user_data(user_data: dict) -> dict:
        """Return a copy of user_data with PII fields masked for safe logging."""
        masked = user_data.copy()
        if 'email' in masked:
            masked['email'] = PIIMaskingUtil.mask_email(masked['email'])
        if 'phone_number' in masked:
            masked['phone_number'] = PIIMaskingUtil.mask_phone(masked['phone_number'])
        if 'address' in masked:
            if isinstance(masked['address'], dict):
                addr_copy = masked['address'].copy()
                if 'street' in addr_copy:
                    addr_copy['street'] = PIIMaskingUtil.mask_address(addr_copy['street'])
                masked['address'] = addr_copy
            elif isinstance(masked['address'], str):
                masked['address'] = PIIMaskingUtil.mask_address(masked['address'])
        if 'ssn' in masked:
            masked['ssn'] = '***-**-' + masked['ssn'][-4:] if len(masked['ssn']) >= 4 else '***'
        return masked


class UserDataValidator:
    """Validates user data before publishing."""

    REQUIRED_FIELDS = ['user_id', 'email']

    @staticmethod
    def validate(user_data: dict) -> tuple[bool, Optional[str]]:
        for field in UserDataValidator.REQUIRED_FIELDS:
            if field not in user_data or not user_data[field]:
                return False, f"Missing required field: {field}"

        email = user_data.get('email', '')
        if '@' not in email or '.' not in email.split('@')[-1]:
            return False, "Invalid email format"

        phone = user_data.get('phone_number')
        if phone:
            digits = ''.join(c for c in phone if c.isdigit())
            if len(digits) < 10:
                return False, "Invalid phone number format"

        return True, None


class SQSUserDataPublisher:
    """
    SQS Publisher for user data messages containing PII.

    Implements secure handling of PII data including:
    - Masking PII in all log outputs
    - Message validation before publishing
    - Server-side encryption via SQS queue configuration
    - Message deduplication support for FIFO queues
    - Structured message attributes for filtering
    """

    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        is_fifo_queue: bool = False,
        message_group_id: str = 'user-data-group',
    ):
        self.queue_url = queue_url
        self.is_fifo_queue = is_fifo_queue
        self.message_group_id = message_group_id
        self.masker = PIIMaskingUtil()
        self.validator = UserDataValidator()

        session_kwargs = {'region_name': region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs['aws_access_key_id'] = aws_access_key_id
            session_kwargs['aws_secret_access_key'] = aws_secret_access_key

        session = boto3.Session(**session_kwargs)
        self.sqs_client = session.client('sqs')

        logger.info("SQSUserDataPublisher initialized for queue: %s", queue_url)

    def _build_message_body(self, user_data: dict, event_type: str) -> str:
        """Build the message body with metadata envelope."""
        message = {
            'message_id': str(uuid.uuid4()),
            'event_type': event_type,
            'timestamp': datetime.utcnow().isoformat() + 'Z',
            'version': '1.0',
            'data_classification': 'PII',
            'payload': user_data,
        }
        return json.dumps(message, default=str)

    def _build_message_attributes(self, user_data: dict, event_type: str) -> dict:
        """Build SQS message attributes for filtering (no PII in attributes)."""
        attributes = {
            'EventType': {
                'DataType': 'String',
                'StringValue': event_type,
            },
            'DataClassification': {
                'DataType': 'String',
                'StringValue': 'PII',
            },
            'UserId': {
                'DataType': 'String',
                'StringValue': str(user_data.get('user_id', 'unknown')),
            },
            'Timestamp': {
                'DataType': 'String',
                'StringValue': datetime.utcnow().isoformat() + 'Z',
            },
        }
        return attributes

    def publish_user_created(self, user_data: dict) -> Optional[str]:
        """Publish a user created event."""
        return self._publish(user_data, 'USER_CREATED')

    def publish_user_updated(self, user_data: dict) -> Optional[str]:
        """Publish a user updated event."""
        return self._publish(user_data, 'USER_UPDATED')

    def publish_user_deleted(self, user_data: dict) -> Optional[str]:
        """Publish a user deleted event."""
        return self._publish(user_data, 'USER_DELETED')

    def publish_user_pii_updated(self, user_data: dict) -> Optional[str]:
        """Publish a PII-specific update event (e.g., email change, address change)."""
        return self._publish(user_data, 'USER_PII_UPDATED')

    def _publish(self, user_data: dict, event_type: str) -> Optional[str]:
        """
        Core publish method. Validates, builds, and sends the message.
        Returns the SQS MessageId on success, or None on failure.
        """
        # Validate
        is_valid, error_msg = self.validator.validate(user_data)
        if not is_valid:
            logger.error(
                "Validation failed for user %s: %s",
                user_data.get('user_id', 'unknown'),
                error_msg,
            )
            raise ValueError(f"User data validation failed: {error_msg}")

        # Build message
        message_body = self._build_message_body(user_data, event_type)
        message_attributes = self._build_message_attributes(user_data, event_type)

        # Log with masked PII
        masked_data = self.masker.mask_user_data(user_data)
        logger.info(
            "Publishing %s event for user %s with masked data: %s",
            event_type,
            user_data.get('user_id'),
            json.dumps(masked_data, default=str),
        )

        # Build SQS send params
        send_kwargs = {
            'QueueUrl': self.queue_url,
            'MessageBody': message_body,
            'MessageAttributes': message_attributes,
        }

        if self.is_fifo_queue:
            send_kwargs['MessageGroupId'] = self.message_group_id
            dedup_id = str(uuid.uuid4())
            send_kwargs['MessageDeduplicationId'] = dedup_id

        try:
            response = self.sqs_client.send_message(**send_kwargs)
            message_id = response.get('MessageId')
            logger.info(
                "Successfully published %s event for user %s. MessageId: %s",
                event_type,
                user_data.get('user_id'),
                message_id,
            )
            return message_id

        except ClientError as e:
            error_code = e.response['Error']['Code']
            logger.error(
                "Failed to publish %s event for user %s. Error: %s - %s",
                event_type,
                user_data.get('user_id'),
                error_code,
                e.response['Error']['Message'],
            )
            raise

    def publish_batch(self, user_data_list: list[dict], event_type: str) -> dict:
        """
        Publish a batch of user data messages (up to 10 per SQS batch).
        Returns a dict with 'successful' and 'failed' message IDs.
        """
        results = {'successful': [], 'failed': []}

        # SQS allows max 10 messages per batch
        batch_size = 10
        for i in range(0, len(user_data_list), batch_size):
            batch = user_data_list[i:i + batch_size]
            entries = []

            for idx, user_data in enumerate(batch):
                is_valid, error_msg = self.validator.validate(user_data)
                if not is_valid:
                    logger.error(
                        "Validation failed for user %s in batch: %s",
                        user_data.get('user_id', 'unknown'),
                        error_msg,
                    )
                    results['failed'].append({
                        'user_id': user_data.get('user_id', 'unknown'),
                        'error': error_msg,
                    })
                    continue

                entry_id = f"msg-{i + idx}"
                message_body = self._build_message_body(user_data, event_type)
                message_attributes = self._build_message_attributes(user_data, event_type)

                entry = {
                    'Id': entry_id,
                    'MessageBody': message_body,
                    'MessageAttributes': message_attributes,
                }

                if self.is_fifo_queue:
                    entry['MessageGroupId'] = self.message_group_id
                    entry['MessageDeduplicationId'] = str(uuid.uuid4())

                entries.append(entry)

                masked_data = self.masker.mask_user_data(user_data)
                logger.info(
                    "Batch entry prepared for user %s: %s",
                    user_data.get('user_id'),
                    json.dumps(masked_data, default=str),
                )

            if not entries:
                continue

            try:
                response = self.sqs_client.send_message_batch(
                    QueueUrl=self.queue_url,
                    Entries=entries,
                )

                for success in response.get('Successful', []):
                    results['successful'].append(success['MessageId'])
                    logger.info("Batch message sent successfully: %s", success['MessageId'])

                for failure in response.get('Failed', []):
                    results['failed'].append({
                        'id': failure['Id'],
                        'error': failure.get('Message', 'Unknown error'),
                        'sender_fault': failure.get('SenderFault', False),
                    })
                    logger.error("Batch message failed: %s - %s", failure['Id'], failure.get('Message'))

            except ClientError as e:
                logger.error("Batch send failed: %s", e.response['Error']['Message'])
                raise

        logger.info(
            "Batch publish complete. Successful: %d, Failed: %d",
            len(results['successful']),
            len(results['failed']),
        )
        return results


